/*============================ Variables CSS ========================*/
:root {
  --orange: #94d5e6;
  --light-gray: #f5f5f5;
  --text-dark: #333;
  --text-light: #fff;
  --hover-bg: #ffe7d6;
  --transition: all 0.3s ease;
  --radius: 10px;
  font-family: 'Poppins', sans-serif;
}

/* === General === */
body {
  margin: 0;
  background: var(--light-gray);
  color: var(--text-dark);
}

/* 🌞 Modo claro por defecto */
body {
  background-color: rgb(22, 22, 22);
  color: rgb(250, 250, 250);
  transition: background-color 0.5s ease, color 0.5s ease;
}


body.dark-mode {
  background-color: #121212;
  color: #f0f0f0;
}
a {
  text-decoration: none;
  color: inherit;
}
a:hover {
  color: var(--orange);
}
/* === Navbar === */
.navbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  background-color: #99d6e0;
  padding: 8px 20px;
  font-family: 'Helvetica Neue', sans-serif;
  position: relative;
  top: 0;
  z-index: 10;
  height: 50px;
  box-sizing: border-box;
}

.logo-fig img {
  max-height: 58px; /* el logo nunca será más alto que esto */
  width: auto; /* mantiene proporción */
  object-fit: contain;
  margin-right: 1px;
  display: block; /* elimina efectos de línea base */
  align-items: left;
}

.logo {
  display: flex;
  align-items: center;
  cursor: pointer;
}

.logo-text {
  font-size: 20px;
  font-weight: 600;
  color: #0c2147;
  margin-left: 5px;
}

.search-bar {
