  border-radius: 8px;
  font-size: 0.9rem;
  border: none;
  cursor: pointer;
  transition: 0.3s;
}

.btn-canceler {
  background: #f3f3f3;
  color: #333;
}

.btn-canceler:hover { background: #e5e5e5; }

.btn-savever {
  background: var(--accent-color, #83e2fa);
  color: white;
}

.btn-savever:hover { background: #9af1d4; }

/* Layout general */
.new-storys {
  display: flex;
  padding: 2rem;
  gap: 2rem;
  background: #fafafa;
  margin: auto;
  max-width: 1000px;
