  border: 0.1px solid #e7e7e7;
  padding: 0.7rem;
  border-radius: 12px;
  box-shadow: 0 2px 10px rgba(255, 255, 255, 0.1);
}

.story-cover {
  width: 200px;
  display: flex;
  justify-content: center;
}
